/* =========================================================
   SCRIPT COMPLETO DE IMPORTAÇÃO SEGURA
   - Importa tb_endereco a partir do insert antigo
   - Importa tb_titular a partir do insert antigo
   - Usa o 2º campo de tb_titular como id_endereco
   - Só grava id_endereco se existir em tb_endereco
   - Converte data_nascimento para DATE
   - Converte genero para ENUM('M','F','Outro')
   - Trata datas inválidas como NULL
   - Mantém id_familia como NULL
   ========================================================= */

START TRANSACTION;

