    naturalidade VARCHAR(100) NULL,
    cidade VARCHAR(100) NULL,
    tempo_moradia_anos VARCHAR(100) NULL,
    registration_date TIMESTAMP NULL,
    registration_date_update TIMESTAMP NULL
);

