/* =========================================================
   2) IMPORTA PARA tb_endereco REAL
   ========================================================= */
INSERT INTO tb_endereco (
    id,
    cep,
    bairro,
    rua,
    numero,
    referencia,
    nacionalidade,
    naturalidade,
    cidade,
    tempo_moradia_anos,
    registration_date,
    registration_date_update
)
SELECT
    e.id_old AS id,
    NULLIF(TRIM(e.cep), '') AS cep,
    NULLIF(TRIM(e.bairro), '') AS bairro,
    NULLIF(TRIM(e.rua), '') AS rua,
    NULLIF(TRIM(e.numero), '') AS numero,
    NULLIF(TRIM(e.referencia), '') AS referencia,
    NULLIF(TRIM(e.nacionalidade), '') AS nacionalidade,
    NULLIF(TRIM(e.naturalidade), '') AS naturalidade,
    NULLIF(TRIM(e.cidade), '') AS cidade,
    NULLIF(TRIM(e.tempo_moradia_anos), '') AS tempo_moradia_anos,
    e.registration_date,
    e.registration_date_update
FROM tb_endereco_import e
ON DUPLICATE KEY UPDATE
    cep = VALUES(cep),
    bairro = VALUES(bairro),
    rua = VALUES(rua),
    numero = VALUES(numero),
    referencia = VALUES(referencia),
    nacionalidade = VALUES(nacionalidade),
    naturalidade = VALUES(naturalidade),
    cidade = VALUES(cidade),
    tempo_moradia_anos = VALUES(tempo_moradia_anos),
    registration_date = VALUES(registration_date),
    registration_date_update = VALUES(registration_date_update);

/* =========================================================
   3) TABELA TEMPORÁRIA DE TITULAR
   ========================================================= */
DROP TABLE IF EXISTS tb_titular_import;

CREATE TABLE tb_titular_import (
    id_old INT NULL,
    id_endereco_old INT NULL,
    nome_completo VARCHAR(100) NULL,
    nome_social VARCHAR(100) NULL,
    cor_cliente VARCHAR(50) NULL,
    nome_mae VARCHAR(100) NULL,
    telefone VARCHAR(20) NULL,
    data_nascimento_old VARCHAR(20) NULL,
    idade INT NULL,
    genero_old VARCHAR(20) NULL,
    estado_civil VARCHAR(50) NULL,
    rg VARCHAR(20) NULL,
    cpf VARCHAR(15) NULL,
    nis VARCHAR(30) NULL,
    status_cliente VARCHAR(30) NULL,
    registration_date TIMESTAMP NULL,
    registration_date_update TIMESTAMP NULL
);

INSERT INTO tb_titular_import (
    id_old,
    id_endereco_old,
    nome_completo,
    nome_social,
    cor_cliente,
    nome_mae,
    telefone,
    data_nascimento_old,
    idade,
    genero_old,
    estado_civil,
    rg,
    cpf,
    nis,
    status_cliente,
    registration_date,
