   4) IMPORTA PARA tb_titular REAL
   ========================================================= */
INSERT INTO tb_titular (
    id,
    id_endereco,
    id_familia,
    nome_completo,
    nome_social,
    cor_cliente,
    nome_mae,
    telefone,
    data_nascimento,
    idade,
    genero,
    estado_civil,
    rg,
    cpf,
    nis,
    status_cliente,
    registration_date,
    registration_date_update
)
SELECT
    t.id_old AS id,
    CASE
        WHEN t.id_endereco_old IS NULL THEN NULL
        WHEN EXISTS (
            SELECT 1
            FROM tb_endereco e
            WHERE e.id = t.id_endereco_old
        ) THEN t.id_endereco_old
        ELSE NULL
    END AS id_endereco,
    NULL AS id_familia,
    NULLIF(TRIM(t.nome_completo), '') AS nome_completo,
    NULLIF(TRIM(t.nome_social), '') AS nome_social,
    NULLIF(TRIM(t.cor_cliente), '') AS cor_cliente,
    NULLIF(TRIM(t.nome_mae), '') AS nome_mae,
    NULLIF(TRIM(t.telefone), '') AS telefone,
    CASE
        WHEN t.data_nascimento_old IS NULL OR TRIM(t.data_nascimento_old) = '' THEN NULL
        WHEN TRIM(t.data_nascimento_old) NOT REGEXP '^[0-9]{2}/[0-9]{2}/[0-9]{4}$' THEN NULL
        WHEN CAST(SUBSTRING(TRIM(t.data_nascimento_old), 1, 2) AS UNSIGNED) NOT BETWEEN 1 AND 31 THEN NULL
        WHEN CAST(SUBSTRING(TRIM(t.data_nascimento_old), 4, 2) AS UNSIGNED) NOT BETWEEN 1 AND 12 THEN NULL
        WHEN CAST(SUBSTRING(TRIM(t.data_nascimento_old), 4, 2) AS UNSIGNED) IN (4,6,9,11)
             AND CAST(SUBSTRING(TRIM(t.data_nascimento_old), 1, 2) AS UNSIGNED) > 30 THEN NULL
        WHEN CAST(SUBSTRING(TRIM(t.data_nascimento_old), 4, 2) AS UNSIGNED) = 2
             AND CAST(SUBSTRING(TRIM(t.data_nascimento_old), 1, 2) AS UNSIGNED) > 29 THEN NULL
        ELSE STR_TO_DATE(TRIM(t.data_nascimento_old), '%d/%m/%Y')
    END AS data_nascimento,
    t.idade,
    CASE
        WHEN UPPER(TRIM(t.genero_old)) IN ('MASCULINO', 'M') THEN 'M'
        WHEN UPPER(TRIM(t.genero_old)) IN ('FEMININO', 'F') THEN 'F'
        ELSE 'Outro'
    END AS genero,
    NULLIF(TRIM(t.estado_civil), '') AS estado_civil,
    CASE
        WHEN t.rg IS NULL OR TRIM(t.rg) = '' THEN NULL
        ELSE TRIM(t.rg)
    END AS rg,
    CASE
        WHEN t.cpf IS NULL OR TRIM(t.cpf) = '' THEN NULL
        ELSE TRIM(t.cpf)
    END AS cpf,
    CASE
        WHEN t.nis IS NULL OR TRIM(t.nis) = '' THEN NULL
        WHEN REPLACE(REPLACE(REPLACE(TRIM(t.nis), '.', ''), '-', ''), ' ', '') IN ('', '0') THEN NULL
        ELSE TRIM(t.nis)
    END AS nis,
    NULLIF(TRIM(t.status_cliente), '') AS status_cliente,
    t.registration_date,
    t.registration_date_update
FROM tb_titular_import t
ON DUPLICATE KEY UPDATE
    id_endereco = VALUES(id_endereco),
    id_familia = VALUES(id_familia),
    nome_completo = VALUES(nome_completo),
    nome_social = VALUES(nome_social),
    cor_cliente = VALUES(cor_cliente),
    nome_mae = VALUES(nome_mae),
    telefone = VALUES(telefone),
    data_nascimento = VALUES(data_nascimento),
    idade = VALUES(idade),
    genero = VALUES(genero),
    estado_civil = VALUES(estado_civil),
    rg = VALUES(rg),
    cpf = VALUES(cpf),
    nis = VALUES(nis),
    status_cliente = VALUES(status_cliente),
    registration_date = VALUES(registration_date),
    registration_date_update = VALUES(registration_date_update);

/* =========================================================
   5) AJUSTA AUTO_INCREMENT
   ========================================================= */
SET @max_id_endereco = (SELECT IFNULL(MAX(id), 0) + 1 FROM tb_endereco);
SET @sql_endereco = CONCAT('ALTER TABLE tb_endereco AUTO_INCREMENT = ', @max_id_endereco);
PREPARE stmt_endereco FROM @sql_endereco;
EXECUTE stmt_endereco;
DEALLOCATE PREPARE stmt_endereco;

SET @max_id_titular = (SELECT IFNULL(MAX(id), 0) + 1 FROM tb_titular);
SET @sql_titular = CONCAT('ALTER TABLE tb_titular AUTO_INCREMENT = ', @max_id_titular);
PREPARE stmt_titular FROM @sql_titular;
EXECUTE stmt_titular;
DEALLOCATE PREPARE stmt_titular;

/* =========================================================
   6) CONFERÊNCIAS
   ========================================================= */
SELECT COUNT(*) AS total_endereco_import FROM tb_endereco_import;
SELECT COUNT(*) AS total_endereco_final FROM tb_endereco;
SELECT COUNT(*) AS total_titular_import FROM tb_titular_import;
SELECT COUNT(*) AS total_titular_final FROM tb_titular;

SELECT
    t.id,
    t.id_endereco,
    t.nome_completo,
    t.data_nascimento,
    t.idade,
    t.genero,
    t.status_cliente
FROM tb_titular t
ORDER BY t.id DESC
LIMIT 50;

SELECT DISTINCT
    ti.id_endereco_old AS id_endereco_nao_encontrado
FROM tb_titular_import ti
LEFT JOIN tb_endereco e
    ON e.id = ti.id_endereco_old
WHERE ti.id_endereco_old IS NOT NULL
  AND e.id IS NULL
ORDER BY ti.id_endereco_old;

COMMIT;
